    41→type backoffStore struct {
    42→	store cache.Store
    43→}
    44→
    45→func (s *backoffStore) updateBackoffRecord(record backoffRecord) error {
    46→	b, ok, err := s.store.GetByKey(record.key)
    47→	if err != nil {
    48→		return err
    49→	}
    50→
    51→	if !ok {
    52→		err = s.store.Add(&record)
    53→		if err != nil {
    54→			return err
    55→		}
    56→	} else {
    57→		backoffRecord := b.(*backoffRecord)
    58→		backoffRecord.failuresAfterLastSuccess = record.failuresAfterLastSuccess
    59→		backoffRecord.lastFailureTime = record.lastFailureTime
    60→	}
    61→
    62→	return nil
    63→}
    64→
    65→func (s *backoffStore) removeBackoffRecord(jobId string) error {
    66→	b, ok, err := s.store.GetByKey(jobId)
    67→	if err != nil {
    68→		return err
    69→	}
    70→
    71→	if ok {
    72→		err = s.store.Delete(b)
    73→		if err != nil {
    74→			return err
    75→		}
    76→	}
    77→
    78→	return nil
    79→
    80→}
