    82→func newBackoffStore() *backoffStore {
    83→	return &backoffStore{
    84→		store: cache.NewStore(backoffRecordKeyFunc),
    85→	}
    86→}
    87→
    88→var backoffRecordKeyFunc = func(obj interface{}) (string, error) {
    89→	if u, ok := obj.(*backoffRecord); ok {
    90→		return u.key, nil
    91→	}
    92→	return "", fmt.Errorf("could not find key for obj %#v", obj)
    93→}
