    95→func (s *backoffStore) newBackoffRecord(key string, newSucceededPods []*v1.Pod, newFailedPods []*v1.Pod) backoffRecord {
    96→	var backoff *backoffRecord
    97→
    98→	if b, exists, _ := s.store.GetByKey(key); exists {
    99→		old := b.(*backoffRecord)
   100→		backoff = &backoffRecord{
   101→			key:                      old.key,
   102→			failuresAfterLastSuccess: old.failuresAfterLastSuccess,
   103→			lastFailureTime:          old.lastFailureTime,
   104→		}
   105→	} else {
   106→		backoff = &backoffRecord{
   107→			key:                      key,
   108→			failuresAfterLastSuccess: 0,
   109→			lastFailureTime:          nil,
   110→		}
   111→	}
   112→
   113→	sortByFinishedTime(newSucceededPods)
   114→	sortByFinishedTime(newFailedPods)
   115→
   116→	if len(newSucceededPods) == 0 {
   117→		if len(newFailedPods) == 0 {
   118→			return *backoff
   119→		}
   120→
