   122→		lastFailureTime := getFinishedTime(newFailedPods[len(newFailedPods)-1])
   123→		backoff.lastFailureTime = &lastFailureTime
   124→		return *backoff
   125→
   126→	} else {
   127→		if len(newFailedPods) == 0 {
   128→			backoff.failuresAfterLastSuccess = 0
   129→			backoff.lastFailureTime = nil
   130→			return *backoff
   131→		}
   132→
   133→		backoff.failuresAfterLastSuccess = 0
   134→		backoff.lastFailureTime = nil
   135→
   136→		lastSuccessTime := getFinishedTime(newSucceededPods[len(newSucceededPods)-1])
