   154→func sortByFinishedTime(pods []*v1.Pod) {
   155→	sort.Slice(pods, func(i, j int) bool {
   156→		p1 := pods[i]
   157→		p2 := pods[j]
   158→		p1FinishTime := getFinishedTime(p1)
   159→		p2FinishTime := getFinishedTime(p2)
   160→
   161→		return p1FinishTime.Before(p2FinishTime)
   162→	})
   163→}
   164→
   165→// Returns the pod finish time using the following lookups:
   166→// 1. if all containers finished, use the latest time
   167→// 2. if the pod has Ready=False condition, use the last transition time
   168→// 3. if the pod has been deleted, use the `deletionTimestamp - grace_period` to estimate the moment of deletion
   169→// 4. fallback to pod's creation time
   170→//
   171→// Pods owned by Kubelet are marked with Ready=False condition when
   172→// transitioning to terminal phase, thus being handled by (1.) or (2.).
   173→// Orphaned pods are deleted by PodGC, thus being handled by (3.).
   174→func getFinishedTime(p *v1.Pod) time.Time {
   175→	if finishTime := getFinishTimeFromContainers(p); finishTime != nil {
   176→		return *finishTime
   177→	}
   178→	if finishTime := getFinishTimeFromPodReadyFalseCondition(p); finishTime != nil {
   179→		return *finishTime
   180→	}
   181→	if finishTime := getFinishTimeFromDeletionTimestamp(p); finishTime != nil {
   182→		return *finishTime
   183→	}
   184→	// This should not happen in clusters with Kubelet and PodGC running.
   185→	return p.CreationTimestamp.Time
   186→}
   187→
   188→func getFinishTimeFromContainers(p *v1.Pod) *time.Time {
   189→	finishTime := latestFinishTime(nil, p.Status.ContainerStatuses, nil)
   190→	if utilfeature.DefaultFeatureGate.Enabled(features.SidecarContainers) {
   191→		// We need to check InitContainerStatuses here also,
   192→		// because with the sidecar (restartable init) containers,
   193→		// sidecar containers will always finish later than regular containers.
   194→		names := sets.New[string]()
   195→		for _, c := range p.Spec.InitContainers {
   196→			if c.RestartPolicy != nil && *c.RestartPolicy == v1.ContainerRestartPolicyAlways {
   197→				names.Insert(c.Name)
   198→			}
   199→		}
   200→		finishTime = latestFinishTime(finishTime, p.Status.InitContainerStatuses, func(status v1.ContainerStatus) bool {
   201→			return names.Has(status.Name)
   202→		})
   203→	}
   204→	return finishTime
   205→}
