   207→func latestFinishTime(prevFinishTime *time.Time, cs []v1.ContainerStatus, check func(status v1.ContainerStatus) bool) *time.Time {
   208→	var finishTime = prevFinishTime
   209→	for _, containerState := range cs {
   210→		if check != nil && !check(containerState) {
   211→			continue
   212→		}
   213→		if containerState.State.Terminated == nil ||
   214→			containerState.State.Terminated.FinishedAt.Time.IsZero() {
   215→			return nil
   216→		}
   217→		if finishTime == nil || finishTime.Before(containerState.State.Terminated.FinishedAt.Time) {
   218→			finishTime = &containerState.State.Terminated.FinishedAt.Time
   219→		}
   220→	}
   221→	return finishTime
   222→}
