   231→func getFinishTimeFromDeletionTimestamp(p *v1.Pod) *time.Time {
   232→	if p.DeletionTimestamp != nil {
   233→		finishTime := p.DeletionTimestamp.Time.Add(-time.Duration(ptr.Deref(p.DeletionGracePeriodSeconds, 0)) * time.Second)
   234→		return &finishTime
   235→	}
   236→	return nil
   237→}
