   224→func getFinishTimeFromPodReadyFalseCondition(p *v1.Pod) *time.Time {
   225→	if _, c := apipod.GetPodCondition(&p.Status, v1.PodReady); c != nil && c.Status == v1.ConditionFalse && !c.LastTransitionTime.Time.IsZero() {
   226→		return &c.LastTransitionTime.Time
   227→	}
   228→	return nil
   229→}
   230→
   231→func getFinishTimeFromDeletionTimestamp(p *v1.Pod) *time.Time {
   232→	if p.DeletionTimestamp != nil {
   233→		finishTime := p.DeletionTimestamp.Time.Add(-time.Duration(ptr.Deref(p.DeletionGracePeriodSeconds, 0)) * time.Second)
   234→		return &finishTime
   235→	}
   236→	return nil
   237→}
   238→
   239→func (backoff backoffRecord) getRemainingTime(clock clock.WithTicker, defaultBackoff time.Duration, maxBackoff time.Duration) time.Duration {
   240→	return getRemainingTimeForFailuresCount(clock, defaultBackoff, maxBackoff, backoff.failuresAfterLastSuccess, backoff.lastFailureTime)
   241→}
   242→
   243→// getRemainingTimePerIndex returns the remaining time left for a given index to
   244→// create the replacement pods. The number of consecutive pod failures for the
   245→// index is retrieved from the `job-index-failure-count` annotation of the
   246→// last failed pod within the index (represented by `lastFailedPod`).
   247→// The last failed pod is also used to determine the time of the last failure.
   248→func getRemainingTimePerIndex(logger klog.Logger, clock clock.WithTicker, defaultBackoff time.Duration, maxBackoff time.Duration, lastFailedPod *v1.Pod) time.Duration {
   249→	if lastFailedPod == nil {
   250→		// There is no previous failed pod for this index
   251→		return time.Duration(0)
   252→	}
   253→	failureCount := getIndexAbsoluteFailureCount(logger, lastFailedPod) + 1
   254→	lastFailureTime := getFinishedTime(lastFailedPod)
   255→	return getRemainingTimeForFailuresCount(clock, defaultBackoff, maxBackoff, failureCount, &lastFailureTime)
   256→}
   257→
   258→func getRemainingTimeForFailuresCount(clock clock.WithTicker, defaultBackoff time.Duration, maxBackoff time.Duration, failuresCount int32, lastFailureTime *time.Time) time.Duration {
   259→	if failuresCount == 0 {
   260→		return 0
   261→	}
   262→
   263→	backoffDuration := defaultBackoff
   264→	for i := 1; i < int(failuresCount); i++ {
   265→		backoffDuration = backoffDuration * 2
   266→		if backoffDuration >= maxBackoff {
   267→			backoffDuration = maxBackoff
   268→			break
   269→		}
   270→	}
   271→
   272→	timeElapsedSinceLastFailure := clock.Since(*lastFailureTime)
   273→
   274→	if backoffDuration < timeElapsedSinceLastFailure {
   275→		return 0
   276→	}
   277→
   278→	return backoffDuration - timeElapsedSinceLastFailure
   279→}
